import React from 'react';
import TaskCard from './TaskCard';

const TaskList = ({ tasks, users = [], projects = [], onStatusChange, onEdit, onDelete, showHeader = true, onViewAll }) => {
  if (tasks.length === 0) {
    return (
      <div className="empty-state">
        <p>No tasks found. Create your first task to get started!</p>
      </div>
    );
  }

  return (
    <div className="task-list-container">
      {showHeader && (
        <div className="section-header">
          <h2>My Recent Tasks</h2>
          {onViewAll && (
            <button 
              className="view-all"
              onClick={onViewAll}
            >
              View All
            </button>
          )}
        </div>
      )}
      <div className="task-list">
        {tasks.map(task => (
          <TaskCard 
            key={task.id} 
            task={task} 
            users={users} 
            projects={projects}
            onStatusChange={onStatusChange}
            onEdit={onEdit}
            onDelete={onDelete}
          />
        ))}
      </div>
    </div>
  );
};

export default TaskList;
